uint64_t ControlAnalysis::_computeHash(const __lcm_hash_ptr *p)
{
    const __lcm_hash_ptr *fp;
    for(fp = p; fp != NULL; fp = fp->parent)
        if(fp->v == ControlAnalysis::getHash)
            return 0;
    const __lcm_hash_ptr cp = { p, ControlAnalysis::getHash };

    uint64_t hash = 0xdffec0d132df70a8LL +
         lcm_interface::Header::_computeHash(&cp);

    return (hash<<1) + ((hash>>63)&1);
}

